class BankAccount:
    def __init__(self, account_number, balance, currency):
        self.account_number = account_number
        self.balance = balance
        self.currency = currency

    def withdraw(self, amount):
        if amount > self.balance:
            print("Insufficient balance")
        else:
            self.balance -= amount
            print(f"Withdrawal successful. New balance: {self.balance} {self.currency}")

class SavingsAccount(BankAccount):
    def withdraw(self, amount):
        # Enforce minimum balance of $100
        if self.balance - amount < 100:
            print("Withdrawal denied: Minimum balance of $100 required")
        else:
            super().withdraw(amount)

class LoanAccount(BankAccount):
    def withdraw(self, amount):
        # Allow overdraft up to $500
        if self.balance - amount < -500:
            print("Withdrawal denied: Overdraft limit exceeded")
        else:
            self.balance -= amount
            print(f"Withdrawal successful. New balance: {self.balance} {self.currency}")

def default_test():
    savings = SavingsAccount("123456789", 1000, "USD")
    checking = LoanAccount("987654321", 500, "USD")

    print("Savings Account Balance:", savings.balance)
    savings.withdraw(950)  # Should fail due to minimum balance requirement
    savings.withdraw(800)  # Should succeed

    print("Checking Account Balance:", checking.balance)
    checking.withdraw(900)  # Should succeed due to overdraft
    checking.withdraw(2000)  # Should fail due to overdraft limit
